#include <stdio.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>

int main(void) {
    struct mq_attr attr;
    attr.mq_flags = 0;
    attr.mq_maxmsg = 10;
    attr.mq_msgsize = 128;
    attr.mq_curmsgs = 0;

    mqd_t mq = mq_open("/kf_mq_create", O_CREAT | O_RDWR, 0644, &attr);
    struct mq_attr cur;
    mq_getattr(mq, &cur);
    printf("maxmsg=%ld msgsize=%ld curmsgs=%ld\n",
           cur.mq_maxmsg, cur.mq_msgsize, cur.mq_curmsgs);
    mq_close(mq);
    mq_unlink("/kf_mq_create");
    return 0;
}

